function normalizeInnerQuotes(s) {
  if (!s || typeof s !== "string") return s;

  s = s.replace(/[״”“]/g, '"');
  s = s.replace(/([\u0590-\u05FF0-9A-Za-z])"(?=[\u0590-\u05FF0-9A-Za-z])/g, "$1״");
  s = s.replace(/[\u202A-\u202E\u2066-\u2069]/g, "");
  return s;
}

function makeFilenameSafe(s) {
  if (!s) return "";
  return String(s)
    .normalize("NFKD")
    .replace(/[^\p{L}\p{N}\s]+/gu, "")
    .trim()
    .replace(/\s+/g, "_")
    .replace(/-+/g, "");
}

const raw = $json.output ?? $json;
let plan = raw;
if (typeof raw === "string") {
  // Remove markdown code fences, e.g. ```json or ```
  const removeFences = s => s.replace(/```(?:json)?|```/gi, '').trim();
  const cleaned = normalizeInnerQuotes(removeFences(raw));
  plan = JSON.parse(cleaned);
}

// ✅ IMPORTANT: handle array wrapper: [ { hero, sections } ]
if (Array.isArray(plan)) {
  plan = plan[0] || {};
}

const out = [];

// HERO
if (plan?.hero?.prompt && String(plan.hero.prompt).trim()) {
  out.push({
    json: {
      slot: "hero",
      type: plan.hero.type || "hero",
      prompt: plan.hero.prompt,
      source_text: plan.hero.source_text || "",
      translation_en: plan.hero.translation_en || "",
      h2_text: "",
      alt: plan.hero.source_text || "",
      filename_safe:
        plan.hero.filename_safe ||
        makeFilenameSafe(plan.hero.translation_en || plan.hero.source_text || "hero"),
    },
  });
}

// SECTIONS
(plan?.sections || [])
  .filter(s => s?.prompt && String(s.prompt).trim())
  .forEach((s, i) => {
    out.push({
      json: {
        slot: `section_${i + 1}`,
        type: s.type || "section",
        prompt: s.prompt,
        h2_text: s.h2_text || "",
        source_text: s.source_text || "",
        translation_en: s.translation_en || "",
        alt: s.h2_text || s.source_text || "",
        filename_safe:
          s.filename_safe ||
          makeFilenameSafe(s.translation_en || s.h2_text || `section_${i + 1}`),
      },
    });
  });

return out;

// We receive the callback item from KIE
// In n8n, the JSON for this item looks like:
// { headers: {...}, body: { code, data: { resultJson, taskId, state, ... } }, ... }

const item = $json;

// Safely get the body object
const body = item.body || {};
const data = body.data || {};

let imageUrl = null;
let parsedResult = null;

if (data.resultJson) {
  try {
    // resultJson is a JSON string, so we must parse it
    parsedResult = JSON.parse(data.resultJson);

    if (Array.isArray(parsedResult.resultUrls) && parsedResult.resultUrls.length > 0) {
      imageUrl = parsedResult.resultUrls[0];
    }
  } catch (error) {
    throw new Error('Could not parse resultJson: ' + error.message);
  }
}

return [
  {
    json: {
      imageUrl,              // 👈 this is your final image URL
      state: data.state,     // "success"
      taskId: data.taskId,   // useful for logging
      rawResultJson: data.resultJson
    }
  }
];

const items = $items();
const urls = items.map(i => i.json["Image URL"]).filter(Boolean);

const images = {
  hero: urls[0] || null,
  section_1: urls[1] || null,
  section_2: urls[2] || null,
  section_3: urls[3] || null,
  section_4: urls[4] || null,
};

return [{ json: { images } }];

// Build image upload items where filename_safe comes from translation_en
// (pulled from "Cleaning Image Prompts" node by matching slot).

function cleanHeadingText(s) {
  if (!s) return "";
  return String(s)
    .replace(/<[^>]*>/g, "")
    .replace(/^#+\s*/g, "")
    .replace(/^\d+[\.\)]\s*/g, "")
    .trim();
}

function extractHeadingsFromMarkdown(md) {
  const lines = (md || "").split("\n");
  let h1 = "";
  const h2 = [];

  for (const rawLine of lines) {
    const line = rawLine.trim();

    const m1 = line.match(/^#\s+(.+)$/);
    if (m1 && !h1) {
      h1 = cleanHeadingText(m1[1]);
      continue;
    }

    const m2 = line.match(/^##\s*(.+)$/);
    if (m2) {
      const txt = cleanHeadingText(m2[1]);
      if (txt) h2.push(txt);
    }
  }

  return { h1, h2 };
}

/**
 * ✅ STRICT HEADER-SAFE FILENAME
 * - NO hyphens
 * - NO spaces
 * - NO extension
 * - ASCII only
 */
function toHeaderSafeFilename(str) {
  const s = String(str || "")
    .trim()
    .replace(/\.(png|jpg|jpeg|webp|gif)$/i, "") // strip extension if present
    .normalize("NFKD")
    .replace(/[\u00A0\u2000-\u200B\u202F\u205F\u3000]/g, "") // remove weird spaces
    .replace(/[\u0300-\u036f]/g, "") // accents
    .replace(/[—–]/g, "")           // long dashes
    .replace(/&/g, "and")
    .replace(/['"`]/g, "")
    .replace(/[:;,.!?(){}\[\]|<>]/g, "")
    .replace(/[^a-zA-Z0-9]/g, "")   // ❗ remove EVERYTHING except letters+numbers
    .slice(0, 80);

  return s || "image";
}

// --- Inputs ---
const images = $node["Collect images URLS"].json.images;
const blog = $node["Writing Blog"].json.output || "";
const { h1, h2 } = extractHeadingsFromMarkdown(blog);
const getH2 = (n) => (h2 && h2.length >= n ? h2[n - 1] : "");

// --- Pull translations from Cleaning Image Prompts (by slot) ---
const translationsBySlot = {};
const cleaned = $items("Cleaning Image Prompts") || [];

for (const it of cleaned) {
  const j = it.json || {};
  if (!j.slot) continue;

  const t =
    (typeof j.translation_en === "string" && j.translation_en.trim()) || "";

  if (t) translationsBySlot[j.slot] = t;
}

function safeNameForSlot(slot, fallback) {
  const t = translationsBySlot[slot] || fallback || "image";
  return toHeaderSafeFilename(t);
}

// --- Build items ---
const map = [
  {
    key: "hero",
    slot: "hero",
    url: images.hero,
    filename_safe: safeNameForSlot("hero", "heroimage"),
    alt: h1 || "תמונה ראשית",
  },
  {
    key: "section_1",
    slot: "section_1",
    url: images.section_1,
    filename_safe: safeNameForSlot("section_1", "section1"),
    alt: getH2(4) || "תמונה",
  },
  {
    key: "section_2",
    slot: "section_2",
    url: images.section_2,
    filename_safe: safeNameForSlot("section_2", "section2"),
    alt: getH2(8) || "תמונה",
  },
  {
    key: "section_3",
    slot: "section_3",
    url: images.section_3,
    filename_safe: safeNameForSlot("section_3", "section3"),
    alt: getH2(12) || "תמונה",
  },
  {
    key: "section_4",
    slot: "section_4",
    url: images.section_4,
    filename_safe: safeNameForSlot("section_4", "section4"),
    alt: getH2(16) || "תמונה",
  },
];

// Output only items with URLs
return map
  .filter(x => !!x.url)
  .map(x => ({ json: x }));

function stripHtml(str) {
  return (str || "").replace(/<[^>]*>/g, "").trim();
}

function extractHeadingsFromMarkdown(md) {
  const lines = (md || "").split("\n").map(l => l.trim());

  let h1 = "";
  const h2 = [];

  for (const line of lines) {
    const m1 = line.match(/^#\s+(.+)$/);
    if (m1 && !h1) h1 = stripHtml(m1[1]);

    const m2 = line.match(/^##\s+(.+)$/);
    if (m2) h2.push(stripHtml(m2[1]));
  }

  return { h1, h2 };
}

// ---- INPUT SOURCES ----
const blog = $node["Writing Blog"].json.output || "";
const { h1, h2 } = extractHeadingsFromMarkdown(blog);

// helper: get H2 by index (1-based)
const H2 = (n) => h2[n - 1] || "";

// Targets (these are the headings your image-plan logic uses)
const targets = {
  hero: h1 || "",
  section_1: H2(4) || "",
  section_2: H2(8) || "",
  section_3: H2(12) || "",
  section_4: H2(16) || "",
};

// ---- WordPress media items come as INPUT to this node ----
const wpItems = $input.all().map(i => i.json);

// Helper: pick best WP URL
function wpUrl(m) {
  return (
    (m && typeof m.source_url === "string" && m.source_url) ||
    (m && m.guid && typeof m.guid.rendered === "string" && m.guid.rendered) ||
    ""
  );
}

// Helper: match media item to a target heading
function matchMediaToHeading(media, heading) {
  if (!heading) return false;

  const alt = (media.alt_text || "").trim();
  const title = (media.title && (media.title.raw || media.title.rendered) || "").trim();

  // Strong match: alt_text equals heading
  if (alt && alt === heading) return true;

  // Fallback match: title equals heading
  if (title && title === heading) return true;

  return false;
}

// Build empty structure first
const structuredImages = {
  hero: null,
  section_1: null,
  section_2: null,
  section_3: null,
  section_4: null,
};

// 1) Try to match by alt_text/title to headings
for (const media of wpItems) {
  const url = wpUrl(media);
  if (!url) continue;

  for (const key of Object.keys(structuredImages)) {
    if (structuredImages[key]) continue; // already filled
    if (matchMediaToHeading(media, targets[key])) {
      structuredImages[key] = {
        url,
        alt: targets[key] || (media.alt_text || "")
      };
    }
  }
}

// 2) Fallback by order if some are still missing (hero first, then sections)
const remainingKeys = Object.keys(structuredImages).filter(k => !structuredImages[k]);
if (remainingKeys.length > 0) {
  // take medias that weren't used yet
  const usedUrls = new Set(Object.values(structuredImages).filter(Boolean).map(x => x.url));
  const unused = wpItems
    .map(m => ({ m, url: wpUrl(m) }))
    .filter(x => x.url && !usedUrls.has(x.url));

  let idx = 0;
  for (const key of remainingKeys) {
    const pick = unused[idx++];
    if (!pick) break;

    structuredImages[key] = {
      url: pick.url,
      alt: targets[key] || (pick.m.alt_text || "")
    };
  }
}

// 3) Remove null entries
Object.keys(structuredImages).forEach(
  k => structuredImages[k] === null && delete structuredImages[k]
);

return [
  {
    json: {
      images: structuredImages
    }
  }
];
